import type { ComponentProps } from 'react';
import { Streamdown, defaultRehypePlugins, type StreamdownProps } from 'streamdown';
import { isSafeLinkUrl, isSafeImageUrl } from '@/vendor/announcement-core';

/**
 * react-markdown passes an extra `node` (hast element) to every mapped
 * component. We never forward it to the DOM, so we type it loosely and strip
 * it before spreading the remaining props.
 */
type WithNode = { node?: unknown };

/**
 * Custom `a` renderer. External-only: opens in a new tab with
 * `rel="noopener noreferrer"`, and hard-gates the href through
 * `isSafeLinkUrl` ‚Äî an unsafe scheme (javascript:, data:, file:, ‚Ä¶) drops the
 * link entirely and keeps just the visible text, so a malicious body can never
 * smuggle a script-executing href.
 */
function SafeLink(props: ComponentProps<'a'> & WithNode) {
  const { href, children, node: _node, ...rest } = props;
  if (typeof href !== 'string' || !isSafeLinkUrl(href)) {
    return <span>{children}</span>;
  }
  return (
    <a
      href={href}
      target="_blank"
      rel="noopener noreferrer"
      className="font-medium text-[var(--ann-accent)] underline"
      {...rest}
    >
      {children}
    </a>
  );
}

/**
 * Custom `img` renderer. Only renders sources that pass `isSafeImageUrl`
 * (https / inline data:image only) ‚Äî a plain-http or scripting-scheme src is
 * dropped rather than fetched.
 */
function SafeImage(props: ComponentProps<'img'> & WithNode) {
  const { src, alt, node: _node, ...rest } = props;
  if (typeof src !== 'string' || !isSafeImageUrl(src)) {
    return null;
  }
  return <img src={src} alt={alt ?? ''} className="max-w-full rounded" {...rest} />;
}

const COMPONENTS: StreamdownProps['components'] = {
  a: SafeLink,
  img: SafeImage,
};

/**
 * Rehype plugin list with Streamdown's raw-HTML pass removed. Streamdown's
 * defaults are `{ raw: rehype-raw, sanitize: rehype-sanitize, harden:
 * rehype-harden }`; dropping `raw` means literal HTML in an announcement body
 * stays escaped as text (never parsed into live nodes), while sanitize +
 * harden are kept as defense in depth alongside our own `SafeLink`/`SafeImage`
 * URL gates. KaTeX/math is deliberately NOT added ‚Äî announcements don't need it
 * and it only widens the attack surface.
 */
const SAFE_REHYPE_PLUGINS = Object.entries(defaultRehypePlugins)
  .filter(([name]) => name !== 'raw')
  .map(([, plugin]) => plugin);

interface Props {
  body: string;
}

/**
 * Renders an announcement `body` (restricted markdown) with the same
 * high-quality Streamdown pipeline the chat uses, but locked down for
 * server-driven content: no raw HTML, external-only safe links, safe-scheme
 * images, GFM (bold/lists/tables) and code blocks on, math off. This is the
 * single body renderer shared by every variant so plugin and admin agree
 * exactly on how a body looks.
 */
export function AnnouncementBody(props: Props) {
  const { body } = props;
  return (
    <div className="text-[var(--ann-fg-muted)]">
      <Streamdown
        mode="static"
        parseIncompleteMarkdown={false}
        isAnimating={false}
        shikiTheme={['github-dark', 'github-light']}
        components={COMPONENTS}
        rehypePlugins={SAFE_REHYPE_PLUGINS}
        controls={{ code: true, table: true }}
      >
        {body}
      </Streamdown>
    </div>
  );
}
